   960→		}
   961→
   962→		nfp_err(state->cpp, "NSP HWinfo lookup failed: %d\n", err);
   963→		return err;
   964→	}
   965→
   966→	if (strnlen(buf, size) == size) {
   967→		nfp_err(state->cpp, "NSP HWinfo value not NULL-terminated\n");
   968→		return -EINVAL;
   969→	}
   970→
   971→	return 0;
   972→}
